'use client';

import { useState, useEffect } from 'react';
import dynamic from 'next/dynamic';
import { useClaimStore } from '@/stores/claim-store';
import { calculateAssessmentSummary } from '@/lib/calculations';
import { getVehicleAgeMonths } from '@/lib/calculations/depreciation';
import { Card, CardContent } from '@/components/ui/card';
import { DownloadCloud, Loader2, AlertCircle } from 'lucide-react';

// The PDFViewer uses browser APIs internally, so we MUST dynamically import it without SSR
// Otherwise Next.js will crash during hydration with "window is not defined".
const PDFViewer = dynamic(
  () => import('@react-pdf/renderer').then(mod => mod.PDFViewer),
  { ssr: false, loading: () => <PDFLoadingFallback /> }
);
const PDFDownloadLink = dynamic(
  () => import('@react-pdf/renderer').then(mod => mod.PDFDownloadLink),
  { ssr: false }
);

// We also dynamic import our document to prevent any weird SSR layout calculations
const SurveyReportDocument = dynamic(
  () => import('@/components/pdf/SurveyReportDocument').then(mod => mod.SurveyReportDocument),
  { ssr: false }
);

function PDFLoadingFallback() {
  return (
    <div className="flex flex-col items-center justify-center h-full min-h-[500px] bg-muted/20 border border-border rounded-lg border-dashed">
      <Loader2 className="h-8 w-8 animate-spin text-primary opacity-50 mb-4" />
      <p className="text-sm text-muted-foreground font-medium uppercase tracking-widest animate-pulse">
        Compiling PDF Engine...
      </p>
    </div>
  );
}

export function ReportTab() {
  const { currentClaim, isDirty } = useClaimStore();
  const [mounted, setMounted] = useState(false);

  // Avoid hydration mismatch by waiting for mount
  useEffect(() => {
    setMounted(true);
  }, []);

  if (!currentClaim || !mounted) return <PDFLoadingFallback />;

  // Instantiate the math engine logic live to pass into the PDF
  const ageMonths = getVehicleAgeMonths(
    currentClaim.vehicle.dateOfRegistration,
    currentClaim.vehicle.yearOfManufacture,
    currentClaim.accident.dateAndTime
  );
  const fb = currentClaim.feeBill;
  const summary = calculateAssessmentSummary(
    currentClaim.assessmentRows,
    ageMonths,
    currentClaim.depreciationType,
    fb.salvageValue,
    fb.lessExcess
  );
  
  const pdfFilename = `${currentClaim.vehicle.registrationNumber || 'DRAFT'}-Survey-Report.pdf`;

  return (
    <div className="p-6 lg:p-8 max-w-7xl mx-auto animate-in fade-in slide-in-from-bottom-2 duration-300 h-full flex flex-col">
      <div className="mb-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Final Report</h2>
          <p className="text-muted-foreground text-sm mt-1">Live PDF Preview — Formatted with Offline React-PDF Engine</p>
        </div>
        
        <div className="flex items-center gap-3">
          {/* Export Button Wrapper */}
          {/* @ts-ignore dynamic import drops the typings */}
          <PDFDownloadLink
            document={<SurveyReportDocument claim={currentClaim} summary={summary} />}
            fileName={pdfFilename}
            className="flex-shrink-0"
          >
            {/* @ts-ignore (React-PDF types are sometimes funky with render props) */}
            {({ loading }) => (
              <button
                disabled={loading}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-md font-semibold text-sm transition-all shadow-sm ${
                  loading 
                    ? 'bg-muted text-muted-foreground cursor-not-allowed' 
                    : 'bg-primary text-primary-foreground hover:bg-primary/90 hover:shadow'
                }`}
              >
                {loading ? <Loader2 size={16} className="animate-spin" /> : <DownloadCloud size={16} />}
                {loading ? 'Preparing Document...' : 'Download PDF'}
              </button>
            )}
          </PDFDownloadLink>
        </div>
      </div>

      {isDirty && (
        <div className="mb-4 p-3 bg-amber-soft text-amber border border-amber/20 rounded-md flex items-center gap-2 text-sm font-medium">
          <AlertCircle size={16} />
          You have unsaved changes. The PDF will update live as you type.
        </div>
      )}

      {/* The Actual PDF Viewer Grid */}
      <Card className="flex-1 border-border shadow-md overflow-hidden bg-[#525659]">
        <CardContent className="p-0 w-full h-[calc(100vh-220px)] min-h-[600px]">
          {/* @ts-ignore dynamic import drops the typings */}
          <PDFViewer width="100%" height="100%" className="border-none" showToolbar={true}>
            <SurveyReportDocument claim={currentClaim} summary={summary} />
          </PDFViewer>
        </CardContent>
      </Card>
    </div>
  );
}
