'use client';

import { useUIStore, type AppTab } from '@/stores/ui-store';
import { useProfileStore } from '@/stores/profile-store';
import { useClaimStore } from '@/stores/claim-store';
import {
  LayoutDashboard,
  FileText,
  ScanSearch,
  ClipboardList,
  MapPin,
  Calculator,
  Printer,
  Camera,
  Receipt,
  RotateCcw,
  User,
  Brain,
  Plus,
  FolderOpen,
  ChevronLeft,
  ChevronRight,
  Menu,
  Wifi,
  WifiOff,
  Cloud,
} from 'lucide-react';

interface NavItem {
  id: AppTab;
  label: string;
  icon: React.ReactNode;
  group: 'main' | 'claim' | 'output' | 'settings';
  requiresClaim?: boolean;
}

const NAV_ITEMS: NavItem[] = [
  // ─── Main ──────────────────────────────────────────
  { id: 'dashboard', label: 'Dashboard', icon: <LayoutDashboard size={18} />, group: 'main' },

  // ─── Claim Workflow ────────────────────────────────
  { id: 'documents', label: 'Documents', icon: <FileText size={18} />, group: 'claim', requiresClaim: true },
  { id: 'review', label: 'AI Review', icon: <ScanSearch size={18} />, group: 'claim', requiresClaim: true },
  { id: 'details', label: 'Claim Details', icon: <ClipboardList size={18} />, group: 'claim', requiresClaim: true },
  { id: 'spot', label: 'Spot Survey', icon: <MapPin size={18} />, group: 'claim', requiresClaim: true },
  { id: 'assessment', label: 'Assessment', icon: <Calculator size={18} />, group: 'claim', requiresClaim: true },

  // ─── Output ────────────────────────────────────────
  { id: 'reports', label: 'Reports', icon: <Printer size={18} />, group: 'output', requiresClaim: true },
  { id: 'photos', label: 'Photo Sheet', icon: <Camera size={18} />, group: 'output', requiresClaim: true },
  { id: 'fees', label: 'Fee Bill', icon: <Receipt size={18} />, group: 'output', requiresClaim: true },
  { id: 'reinspection', label: 'Reinspection', icon: <RotateCcw size={18} />, group: 'output', requiresClaim: true },

  // ─── Settings ──────────────────────────────────────
  { id: 'profile', label: 'Profile', icon: <User size={18} />, group: 'settings' },
  { id: 'learning', label: 'Learning', icon: <Brain size={18} />, group: 'settings' },
];

const GROUP_LABELS: Record<string, string> = {
  main: '',
  claim: 'CLAIM WORKFLOW',
  output: 'OUTPUT',
  settings: 'SETTINGS',
};

import { useState, useEffect } from 'react';

export function Sidebar() {
  const [mounted, setMounted] = useState(false);
  const { activeTab, setActiveTab, sidebarCollapsed, toggleSidebar, isOnline, isDriveConnected, driveEmail } = useUIStore();
  const { setNewClaimDialogOpen, setClaimsListOpen } = useUIStore();
  const { getInitials, profile } = useProfileStore();
  const { currentClaim } = useClaimStore();

  useEffect(() => {
    setMounted(true);
  }, []);

  const hasClaim = !!currentClaim;

  const groups = ['main', 'claim', 'output', 'settings'] as const;

  return (
    <>
      {/* Mobile overlay */}
      <div
        className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm lg:hidden"
        style={{ display: useUIStore.getState().sidebarMobileOpen ? 'block' : 'none' }}
        onClick={() => useUIStore.getState().setSidebarMobileOpen(false)}
      />

      <aside
        className={`
          fixed top-0 left-0 z-50 h-full flex flex-col
          bg-white border-r border-[#f0f0f0] shadow-[1px_0_10px_rgba(0,0,0,0.01)]
          transition-all duration-300 ease-in-out
          ${sidebarCollapsed ? 'w-[60px]' : 'w-[250px]'}
          lg:relative
        `}
      >
        {/* ─── Header ──────────────────────────────────── */}
        <div className="flex items-center gap-3 px-4 py-5 border-b border-[#f0f0f0]">
          <div className="flex-shrink-0 w-8 h-8 rounded-lg bg-black flex items-center justify-center text-white text-xs font-bold shadow-sm">
            {getInitials()}
          </div>
          {!sidebarCollapsed && (
            <div className="flex-1 min-w-0">
              <div className="text-sm font-extrabold text-foreground truncate tracking-tight">
                {profile.name || 'Surveyor'}
              </div>
              <div className="text-[11px] font-medium text-muted-foreground truncate">
                {profile.licenceNumber || 'License #'}
              </div>
            </div>
          )}
          <button
            onClick={toggleSidebar}
            className="hidden lg:flex items-center justify-center w-6 h-6 rounded-md hover:bg-zinc-100 text-muted-foreground transition-colors"
          >
            {sidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
          </button>
        </div>

        {/* ─── Quick Actions ───────────────────────────── */}
        <div className={`flex gap-3 px-4 py-4 border-b border-[#f0f0f0] ${sidebarCollapsed ? 'flex-col items-center' : ''}`}>
          <button
            onClick={() => setNewClaimDialogOpen(true)}
            className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-black hover:bg-zinc-800 hover:-translate-y-px active:scale-[0.98] active:translate-y-0 text-white text-xs font-bold flex-1 justify-center transition-all shadow-sm"
            title="New Claim"
          >
            <Plus size={14} />
            {!sidebarCollapsed && 'New Claim'}
          </button>
          {!sidebarCollapsed && (
            <button
              onClick={() => setClaimsListOpen(true)}
              className="flex items-center justify-center w-9 h-9 rounded-lg border border-[#e5e5e5] hover:border-black hover:text-black bg-white text-muted-foreground transition-all shadow-sm active:scale-[0.98]"
              title="Open Claim"
            >
              <FolderOpen size={16} />
            </button>
          )}
        </div>

        {/* ─── Claim Badge ─────────────────────────────── */}
        {hasClaim && !sidebarCollapsed && (
          <div className="mx-4 mt-4 px-3 py-2.5 rounded-lg bg-zinc-50 border border-zinc-200/60 shadow-sm relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-primary" />
            <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest pl-1">
              {currentClaim.surveyType} Survey
            </div>
            <div className="text-sm font-extrabold text-foreground truncate mt-0.5 pl-1 group-hover:text-primary transition-colors">
              {currentClaim.vehicle.registrationNumber || currentClaim.reportNo || 'New Claim'}
            </div>
          </div>
        )}

        {/* ─── Navigation ──────────────────────────────── */}
        <nav className="flex-1 overflow-y-auto py-4 px-3 space-y-5">
          {groups.map((group) => {
            const items = NAV_ITEMS.filter((item) => item.group === group);
            if (!items.length) return null;

            return (
              <div key={group} className="mb-2">
                {GROUP_LABELS[group] && !sidebarCollapsed && (
                  <div className="px-3 pb-2 text-[10px] items-center font-bold text-muted-foreground/50 uppercase tracking-[0.2em]">
                    {GROUP_LABELS[group]}
                  </div>
                )}
                {items.map((item) => {
                  const disabled = item.requiresClaim && !hasClaim;
                  const isActive = activeTab === item.id;

                  return (
                    <button
                      key={item.id}
                      onClick={() => !disabled && setActiveTab(item.id)}
                      disabled={disabled}
                      title={sidebarCollapsed ? item.label : undefined}
                      className={`
                        w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium
                        transition-all duration-200 mb-0.5
                        ${sidebarCollapsed ? 'justify-center' : ''}
                        ${isActive
                          ? 'bg-zinc-100 text-black font-bold shadow-[inset_0_1px_2px_rgba(0,0,0,0.02)]'
                          : disabled
                            ? 'text-muted-foreground/30 cursor-not-allowed'
                            : 'text-muted-foreground hover:bg-zinc-50 hover:text-foreground'
                        }
                      `}
                    >
                      <span className={isActive ? 'text-black' : ''}>{item.icon}</span>
                      {!sidebarCollapsed && <span className="truncate">{item.label}</span>}
                    </button>
                  );
                })}
              </div>
            );
          })}
        </nav>

        {/* ─── Status Bar ──────────────────────────────── */}
        <div className="px-4 py-4 bg-zinc-50 border-t border-[#f0f0f0] space-y-2 h-[80px]">
          {mounted && (!sidebarCollapsed ? (
            <>
              <div className={`flex items-center gap-2 text-[11px] font-semibold tracking-wide ${isOnline ? 'text-emerald-600' : 'text-amber-600'}`}>
                {isOnline ? <Wifi size={14} /> : <WifiOff size={14} />}
                {isOnline ? 'Online' : 'Offline — Data Local'}
              </div>
              <div className={`flex items-center gap-2 text-[11px] font-medium ${isDriveConnected ? 'text-black' : 'text-muted-foreground'}`}>
                <Cloud size={14} />
                {isDriveConnected ? driveEmail : 'Drive Unlinked'}
              </div>
            </>
          ) : (
            <div className="flex flex-col items-center gap-3 pt-1">
              {isOnline ? <Wifi size={14} className="text-emerald-600" /> : <WifiOff size={14} className="text-amber-600" />}
              <Cloud size={14} className={isDriveConnected ? 'text-black' : 'text-muted-foreground'} />
            </div>
          ))}
        </div>
      </aside>
    </>
  );
}

export function MobileMenuButton() {
  return (
    <button
      className="lg:hidden fixed top-3 left-3 z-50 p-2 rounded-lg bg-card border border-border"
      onClick={() => useUIStore.getState().setSidebarMobileOpen(true)}
    >
      <Menu size={20} />
    </button>
  );
}
